// TopBanner.tsx - Front-end React 컴포넌트 핵심 분석 소스
export const TopBanner = ({ moduleType, templateDetail }) => {
  if (!templateDetail) return <></>;
  return (
    <>
      {templateDetail?.map((detail) => (
        <div
          key={detail.benefitSq}
          className={[
            styles.topBanner,
            detail.imageType === "OP01" || detail.imageType === "OP03" ? styles.typePhoto : styles.typeText,
            detail.imageType === "OP01" || detail.imageType === "OP02" ? styles.square : "",
            moduleType === "TB02" ? styles.dimmed : "",
          ].join(" ")}
        >
          <img src={`${IMAGE_PATH}/${detail.bannerImgPath}`} className={styles.banner} alt="bannerImage" />
          {moduleType === "TB02" && (
            <div className={styles.contents}>
              {/* h1 한글 기준 10자 입력 제한 권장 */}
              {detail.title?.split("\n").map((txt) => <h1 key={txt}>{txt}</h1>)}
              {detail.subTitle?.split("\n").map((txt) => <h2 key={txt}>{txt}</h2>)}
              <p className={styles.badge}>{detail.badge}</p>
            </div>
          )}
        </div>
      ))}
    </>
  );
};

