// frmPlanCardNavigation.xfdl.js - 2단 고정 형태 검증 및 메뉴명 Byte 제한 일부
this.checkValidation = function() {
    var chkVal = 0;
    var gridVal = this.dsCardMenuList.rowcount > 0 ? this.divCardNavi.form.grdCardList : this.divCornerNavi.form.grdCornerList;
    var chkCnt = 0;
    var overCnt = 0;
    var bindDs = gridVal.getBindDataset();

    for(var i=0; i < bindDs.rowcount; i++){
        if(bindDs.getColumn(i, "USE_YN_CHK") == 1){
            chkCnt += 1;
            if(this.asciiByteCount(bindDs.getColumn(i, "MENU_NM")) > 10) overCnt += 1;
        }
    }

    if((this.divCardNavi.form.rdoNaviDispType.value == 2 || this.divCornerNavi.form.rdoNaviDispType.value == 2) && (chkCnt < 5 || chkCnt > 8)) {
        this.gfnMessage("2단 고정 형태는 메뉴 5개 이상 ~ 8개 이하로만 등록할 수 있습니다.", "A");
        return false;
    }
    if((this.divCardNavi.form.rdoNaviDispType.value == 2 || this.divCornerNavi.form.rdoNaviDispType.value == 2) && overCnt > 0) {
        this.gfnMessage("2단 고정 형태는 메뉴명이 한글 기준 5자, 영문기준 10자 이내로만 가능합니다", "A");
        return false;
    }
    return true;
};

