// Notice.tsx - Front-end React 유의사항 파서 및 dangerouslySetInnerHTML 매핑 소스
export const Notice = ({ templateDetail }) => {
  if (!templateDetail?.noticeText) return <></>;

  // XSS 공격 방어용 html sanitize 처리 적용
  const sanitizedHtml = useMemo(() => {
    return DOMPurify.sanitize(templateDetail.noticeText, {
      ALLOWED_TAGS: ['p', 'span', 'strong', 'br', 'ul', 'li', 'a', 'font'],
      ALLOWED_ATTR: ['href', 'target', 'style', 'color']
    });
  }, [templateDetail.noticeText]);

  return (
    <div className={styles.noticeContainer}>
      <div
        className={styles.noticeContent}
        dangerouslySetInnerHTML={{ __html: sanitizedHtml }}
      />
    </div>
  );
};

